Create `src/cli/commands/clone.ts`:

```typescript
import type { Command } from 'commander';
import { sendRequest } from '../client.js';
import type { Request } from '../../shared/protocol.js';

export function registerClone(program: Command): void {
  program
    .command('clone')
    .description('Clone the current session with a new goal')
    .argument('<goal>', 'Goal for the cloned session')
    .option('-c, --context <context>', 'Additional background context')
    .option('--strategy', 'Copy strategy.md from source session')
    .option('-n, --name <name>', 'Human-readable name for the clone')
    .action(async (
      goal: string,
      opts: { context?: string; strategy?: boolean; name?: string }
    ) => {
      const sessionId = process.env.SISYPHUS_SESSION_ID;
      if (!sessionId) {
        console.error(
          'Error: SISYPHUS_SESSION_ID not set. ' +
          'Run this from an orchestrator or agent pane.'
        );  // REQ-003
        process.exit(1);
      }

      const request: Request = {
        type: 'clone',
        sessionId,
        goal,
        context: opts.context,
        name: opts.name,
        strategy: opts.strategy ?? false,
      };

      const response = await sendRequest(request);
      if (response.ok) {
        const cloneId = response.data?.sessionId as string;
        const tmuxName = response.data?.tmuxSessionName as string;

        // Output is orchestrator guidance (REQ-013, REQ-015)
        console.log('Session cloned successfully.');
        console.log(`  Clone: ${cloneId}`);
        console.log(`  Tmux:  ${tmuxName}`);
        console.log('');
        console.log(
          `The cloned session now owns: "${goal}"`);
        console.log(
          'This is the other session\'s responsibility. ' +
          'You do not need to monitor it.');
        console.log('');
        console.log('Update your scope:');
        console.log('- Remove cloned work from goal.md');
        console.log('- Update roadmap.md to reflect reduced scope');
        console.log('- Update strategy.md if approach changes');
      } else {
        console.error(`Error: ${response.error}`);
        process.exit(1);
      }
    });
}
```

Register in `src/cli/index.ts` — add import and call `registerClone(program)` after `registerStart`.

Key design choices:
- No `--no-tmux-check` — clone always runs from within a sisyphus pane
- No `SISYPHUS_CWD` reading — cwd comes from the source session via daemon
- Session ID from env only (not positional) — clone is always from current session
